const _ = require('lodash');

async function solve({ includeComponents, limit, difficulty, tags, problems }) {
  // Filter problems by difficulty and tags
  let filtered = problems.filter(p => {
    if (difficulty && p.difficulty !== difficulty) return false;
    if (tags && tags.length > 0) {
      if (!p.tags || !tags.every(t => p.tags.includes(t))) return false;
    }
    return true;
  });

  // Apply limit
  if (limit) filtered = filtered.slice(0, limit);

  // Prepare metadata object
  const metadata = {};

  if (includeComponents) {
    // Aggregate componentLanguageTotals and componentStatusTotals from filtered problems only

    // componentLanguageTotals: count of problems per language (case-insensitive deduplication per problem)
    const languageCounts = {};
    // componentStatusTotals: count of problems per status
    const statusCounts = {};

    for (const p of filtered) {
      // Deduplicate componentLanguages case-insensitively per problem
      const langs = p.componentLanguages || [];
      const uniqueLangs = [...new Set(langs.map(l => l.toLowerCase()))];
      for (const lang of uniqueLangs) {
        languageCounts[lang] = (languageCounts[lang] || 0) + 1;
      }

      const status = p.status || 'unknown';
      statusCounts[status] = (statusCounts[status] || 0) + 1;
    }

    metadata.componentLanguageTotals = languageCounts;
    metadata.componentStatusTotals = statusCounts;
  }

  return { problems: filtered, metadata };
}

module.exports = { solve };
